import React, { useState } from 'react';
import { View, Text, StyleSheet, SafeAreaView, ScrollView, StatusBar, Pressable, Switch, Alert } from 'react-native';
import { usePetStore } from '../stores/petStore';
import { COLORS, SPACING, FONT_SIZES, BORDER_RADIUS } from '../constants/theme';

interface SettingItemProps {
  icon: string;
  title: string;
  subtitle?: string;
  onPress?: () => void;
  rightElement?: React.ReactNode;
}

const SettingItem: React.FC<SettingItemProps> = ({ icon, title, subtitle, onPress, rightElement }) => (
  <Pressable style={styles.settingItem} onPress={onPress} disabled={!onPress}>
    <Text style={styles.settingIcon}>{icon}</Text>
    <View style={styles.settingContent}>
      <Text style={styles.settingTitle}>{title}</Text>
      {subtitle && <Text style={styles.settingSubtitle}>{subtitle}</Text>}
    </View>
    {rightElement}
  </Pressable>
);

export const SettingsScreen: React.FC = () => {
  const pet = usePetStore();
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [vibrationEnabled, setVibrationEnabled] = useState(true);

  const handleReset = () => {
    Alert.alert(
      '重置宠物',
      '确定要重置宠物吗？所有进度将会丢失！',
      [
        { text: '取消', style: 'cancel' },
        { text: '确定', onPress: pet.reset, style: 'destructive' },
      ]
    );
  };

  const getDaysAlive = () => {
    const days = Math.floor((Date.now() - pet.createdAt) / (1000 * 60 * 60 * 24));
    return days;
  };

  return (
    <SafeAreaView style={styles.container}>
      <StatusBar barStyle="dark-content" backgroundColor={COLORS.background} />
      <ScrollView>
        <View style={styles.header}>
          <Text style={styles.title}>设置 ⚙️</Text>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>基本设置</Text>
          <View style={styles.card}>
            <SettingItem
              icon="🔊"
              title="音效"
              subtitle="操作时的声音反馈"
              rightElement={<Switch value={soundEnabled} onValueChange={setSoundEnabled} trackColor={{ true: COLORS.primary }} />}
            />
            <SettingItem
              icon="📳"
              title="震动"
              subtitle="操作时的震动反馈"
              rightElement={<Switch value={vibrationEnabled} onValueChange={setVibrationEnabled} trackColor={{ true: COLORS.primary }} />}
            />
          </View>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>宠物管理</Text>
          <View style={styles.card}>
            <SettingItem
              icon="🔄"
              title="重置宠物"
              subtitle="重新开始养成"
              onPress={handleReset}
            />
          </View>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>宠物信息</Text>
          <View style={styles.card}>
            <View style={styles.infoRow}>
              <Text style={styles.infoLabel}>成长阶段</Text>
              <Text style={styles.infoValue}>
                {pet.stage === 'baby' ? '🐣 幼年期' : 
                 pet.stage === 'young' ? '🐥 青年期' : 
                 pet.stage === 'adult' ? '🐔 成年期' : '🦅 进化体'}
              </Text>
            </View>
            <View style={styles.infoRow}>
              <Text style={styles.infoLabel}>存活天数</Text>
              <Text style={styles.infoValue}>{getDaysAlive()} 天</Text>
            </View>
            <View style={styles.infoRow}>
              <Text style={styles.infoLabel}>亲密度</Text>
              <Text style={styles.infoValue}>{pet.intimacy}%</Text>
            </View>
          </View>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>关于</Text>
          <View style={styles.card}>
            <SettingItem
              icon="📱"
              title="PetPal"
              subtitle="版本 1.0.0"
            />
            <SettingItem
              icon="💖"
              title="made with love"
              subtitle="为孩子们打造的电子宠物"
            />
          </View>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: COLORS.background },
  header: { padding: SPACING.lg, paddingBottom: SPACING.sm },
  title: { fontSize: FONT_SIZES.xxl, fontWeight: 'bold', color: COLORS.primaryDark },
  section: { marginBottom: SPACING.lg, paddingHorizontal: SPACING.md },
  sectionTitle: { fontSize: FONT_SIZES.sm, color: COLORS.textLight, marginBottom: SPACING.sm, marginLeft: SPACING.sm },
  card: { backgroundColor: COLORS.card, borderRadius: BORDER_RADIUS.lg, overflow: 'hidden' },
  settingItem: { flexDirection: 'row', alignItems: 'center', padding: SPACING.md, borderBottomWidth: 1, borderBottomColor: '#F0F0F0' },
  settingIcon: { fontSize: 24, marginRight: SPACING.md },
  settingContent: { flex: 1 },
  settingTitle: { fontSize: FONT_SIZES.md, color: COLORS.text, fontWeight: '500' },
  settingSubtitle: { fontSize: FONT_SIZES.sm, color: COLORS.textLight, marginTop: 2 },
  infoRow: { flexDirection: 'row', justifyContent: 'space-between', padding: SPACING.md, borderBottomWidth: 1, borderBottomColor: '#F0F0F0' },
  infoLabel: { fontSize: FONT_SIZES.md, color: COLORS.text },
  infoValue: { fontSize: FONT_SIZES.md, color: COLORS.primaryDark, fontWeight: '500' },
});
